const items = $input.all();

const jobList = items.map((item, i) => {
  const j = item.json;
  return `${i + 1}. ${j['Job Title '] || 'Unknown Role'} at ${j['Company Name'] || 'Unknown Company'}
   Salary: ${j['Salary'] || 'Not specified'}
   Job Link: ${j['Job Post Link'] || 'N/A'}
   Resume: ${j['Resume URL'] || 'N/A'}
   Cover Letter: ${j['Cover Letter URL'] || 'N/A'}`;
}).join('\n\n');

return [{
  json: {
    totalJobs: items.length,
    jobList: jobList
  }
}];

const items = $input.all();
const matches = items.filter(item => item.json.output && item.json.output.Verdict === true);

if (matches.length === 0) {
  return [{
    json: {
      noMatches: true,
      totalJobsChecked: items.length
    }
  }];
}

// Has matches - return empty so downstream doesn't execute
return [];

const items = $input.all();

return items.map(item => {
  const job = item.json;
  // Map Google Jobs Scraper fields to match downstream node expectations
  return {
    json: {
      ...job,
      descriptionText: job.description || job.descriptionText || '',
      link: job.applyLink || job.jobUrl || job.link || '',
      postedAt: job.date || job.postedAt || '',
      companyWebsite: job.companyUrl || job.companyWebsite || '',
      companyDescription: job.companyDescription || job.description || '',
      applicantsCount: job.applicantsCount || '',
      title: job.title || '',
      companyName: job.companyName || '',
      location: job.location || '',
      salary: job.salary || job.salaryRange || ''
    }
  };
});

const jobs = $input.all();

// Step 1: Get latest CSV URL from GOV.UK API
let sponsorNames = new Set();
try {
  const govResp = await $helpers.httpRequest({
    method: 'GET',
    url: 'https://www.gov.uk/api/content/government/publications/register-of-licensed-sponsors-workers'
  });
  const attachments = govResp?.details?.attachments || [];
  const csv = attachments.find(a => a.url?.endsWith('.csv') || a.file_extension === 'csv');
  if (csv?.url) {
    // Step 2: Download the CSV
    const csvText = await $helpers.httpRequest({ method: 'GET', url: csv.url });
    // Step 3: Parse — column 0 is Organisation Name, skip header row
    const lines = csvText.split('\n').slice(1);
    const stripSuffixes = /\s*(ltd|limited|plc|llp|inc|llc|group|uk|services|solutions|international|global)\s*\.?$/gi;
    for (const line of lines) {
      const col = line.split(',')[0]?.replace(/^"|"$/g, '').trim().toLowerCase();
      if (col) {
        sponsorNames.add(col);
        sponsorNames.add(col.replace(stripSuffixes, '').trim());
      }
    }
  }
} catch (e) {
  // Register unavailable — fall back to keyword-only filtering
  console.log('Sponsor register unavailable, using keyword filter only:', e.message);
}

const sponsorKeywords = [
  'visa sponsorship', 'sponsorship provided', 'we sponsor', 'tier 2',
  'skilled worker visa', 'certificate of sponsorship', 'cos provided',
  'sponsorship available', 'happy to sponsor'
];

const stripSuffixesRe = /\s*(ltd|limited|plc|llp|inc|llc|group|uk|services|solutions|international|global)\s*\.?$/gi;

return jobs
  .map(item => {
    const job = item.json;
    const co = (job.companyName || '').toLowerCase().trim();
    const desc = (job.descriptionText || '').toLowerCase();
    const title = (job.title || '').toLowerCase();

    // Check 1: Company name in sponsor register (exact + normalised)
    const coNorm = co.replace(stripSuffixesRe, '').trim();
    const inRegister = sponsorNames.size > 0 && (
      sponsorNames.has(co) ||
      sponsorNames.has(coNorm) ||
      (coNorm.length > 4 && [...sponsorNames].some(s => s.includes(coNorm) || coNorm.includes(s)))
    );

    // Check 2: Job description or title mentions sponsorship keywords
    const mentionsSponsorship = sponsorKeywords.some(kw => desc.includes(kw) || title.includes(kw));

    const sponsorMatch = inRegister ? 'register' : mentionsSponsorship ? 'description' : null;
    if (!sponsorMatch) return null;

    return { json: { ...job, sponsorMatch } };
  })
  .filter(Boolean);

